package com.example.projecthub.model;

import jakarta.persistence.*;
import lombok.Data;

@Entity
@Data
public class Review {

    @Id
    @GeneratedValue(strategy = GenerationType.AUTO)
    private Long id;
    private int rating;

    private String comment;

    @ManyToOne
    @JoinColumn(name = "project_id")
    private Project project;

    @ManyToOne
    @JoinColumn(name = "user_id")
    private User user;
}

package com.example.projecthub.model;

import jakarta.persistence.*;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.time.LocalDateTime;

/**
 * Entity representing a user's review/rating for a project.
 * 
 * Contains:
 * - Rating score (1-5 scale)
 * - Comment text provided by reviewer
 * - Relationships to user and project
 * - Audit timestamps for tracking review lifecycle
 * 
 * Enforces:
 * - One review per user per project (business logic validation)
 * - Rating must be between 1 and 5
 * - Non-empty comment field
 * 
 * @author Project Hub Team
 * @version 1.0
 */
@Entity
@Data
@NoArgsConstructor
@Table(name = "reviews", uniqueConstraints = @UniqueConstraint(columnNames = {"user_id", "project_id"}))
public class Review {

    /**
     * Unique identifier for the review.
     * Auto-generated primary key.
     */
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    /**
     * Rating score from 1 to 5.
     * 1 = Poor, 5 = Excellent
     * Must be validated in service layer.
     */
    @Column(nullable = false)
    private int rating;

    /**
     * Detailed review comment provided by the reviewer.
     * Can contain feedback, pros, cons, and recommendations.
     */
    @Column(nullable = false, length = 1000)
    private String comment;

    /**
     * Reference to the project being reviewed.
     * Multiple reviews can reference same project.
     * Cascade delete is handled by Project entity.
     */
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "project_id", nullable = false)
    private Project project;

    /**
     * Reference to the user who submitted the review.
     * Each user can have multiple reviews across different projects.
     */
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "user_id", nullable = false)
    private User user;

    /**
     * Timestamp when the review was created.
     * Set automatically on entity creation.
     */
    @Column(nullable = false, updatable = false)
    private LocalDateTime createdAt;

    /**
     * Timestamp when the review was last updated.
     * Updated whenever the review is modified.
     */
    @Column(nullable = false)
    private LocalDateTime updatedAt;

    /**
     * Lifecycle callback - sets creation timestamp before persisting.
     * Called once when review is first saved to database.
     */
    @PrePersist
    protected void onCreate() {
        this.createdAt = LocalDateTime.now();
        this.updatedAt = LocalDateTime.now();
    }

    /**
     * Lifecycle callback - updates modification timestamp before update.
     * Called every time the review is updated in database.
     */
    @PreUpdate
    protected void onUpdate() {
        this.updatedAt = LocalDateTime.now();
    }
}
